export interface Scenario {
  /**
   * @displayName Scenario
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Scenario Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  scenarioname: string;
  /**
   * @displayName Failed
   */
  failed?: number;
  /**
   * @displayName Passed
   */
  passed?: number;
  /**
   * @displayName Pass Rate Percent
   */
  passratepercent?: number;
  /**
   * @displayName Total Tests
   */
  totaltests?: number;
  /**
   * @displayName Test Script
   * @description Explicit LLM-generated Playwright automation script
   */
  testScript?: string;
}

export const _Scenario = 'Scenario' as const;